query:
-- Verificar notificações de teste
SELECT COUNT(*) as test_notifications FROM notifications WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- Verificar membros de bolão de teste
SELECT COUNT(*) as test_pool_members FROM pool_members WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- Verificar logs de admin de teste
SELECT COUNT(*) as test_logs FROM admin_logs WHERE actorId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

